begin;
create extension if not exists pgcrypto;
create type handover_status as enum ('DRAFT','SUBMITTED','PENDING_RECEIVER_CONFIRMATION','SUPPLEMENT_REQUESTED','RESUBMITTED','CONFIRMED','COMPLETED','CANCELLED','OVERDUE');
create type participant_type as enum ('GIVER','RECEIVER','SUPERVISOR','APPROVER');
create type item_priority as enum ('LOW','NORMAL','HIGH','URGENT');
create type finance_status as enum ('DRAFT','PENDING_CONFIRMATION','CONFIRMED','DISCREPANCY','RECONCILED');
create table organizations(id uuid primary key default gen_random_uuid(),name text not null,code text not null unique,created_at timestamptz not null default now());
create table branches(id uuid primary key default gen_random_uuid(),organization_id uuid not null references organizations(id),name text not null,code text not null,address text,timezone text not null default 'Asia/Ho_Chi_Minh',created_at timestamptz not null default now(),unique(organization_id,code));
create table profiles(id uuid primary key references auth.users(id) on delete cascade,organization_id uuid not null references organizations(id),full_name text not null,email text not null,is_active boolean not null default true,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table roles(id uuid primary key default gen_random_uuid(),code text not null unique,name text not null);
create table permissions(id uuid primary key default gen_random_uuid(),code text not null unique,name text not null);
create table role_permissions(role_id uuid references roles(id) on delete cascade,permission_id uuid references permissions(id) on delete cascade,primary key(role_id,permission_id));
create table branch_memberships(id uuid primary key default gen_random_uuid(),profile_id uuid not null references profiles(id),branch_id uuid not null references branches(id),role_id uuid not null references roles(id),is_active boolean not null default true,created_at timestamptz not null default now(),unique(profile_id,branch_id));
create table shift_definitions(id uuid primary key default gen_random_uuid(),organization_id uuid not null references organizations(id),name text not null,code text not null,start_time time not null,end_time time not null,unique(organization_id,code));
create table shift_instances(id uuid primary key default gen_random_uuid(),organization_id uuid not null references organizations(id),branch_id uuid not null references branches(id),shift_definition_id uuid references shift_definitions(id),shift_code text not null,starts_at timestamptz not null,ends_at timestamptz not null,status text not null default 'OPEN',created_at timestamptz not null default now());
create table shift_assignments(id uuid primary key default gen_random_uuid(),shift_instance_id uuid not null references shift_instances(id),profile_id uuid not null references profiles(id),assignment_type text not null,unique(shift_instance_id,profile_id));
create sequence handover_code_sequence;
create function generate_handover_code() returns text language sql as $$select 'BG-'||to_char(now() at time zone 'Asia/Ho_Chi_Minh','YYYYMMDD')||'-'||lpad(nextval('handover_code_sequence')::text,5,'0')$$;
create table handovers(id uuid primary key default gen_random_uuid(),organization_id uuid not null references organizations(id),branch_id uuid not null references branches(id),shift_instance_id uuid not null references shift_instances(id),code text not null unique default generate_handover_code(),status handover_status not null default 'DRAFT',notes text,version integer not null default 1,created_by uuid not null references profiles(id),submitted_at timestamptz,confirmed_at timestamptz,completed_at timestamptz,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table handover_participants(id uuid primary key default gen_random_uuid(),organization_id uuid not null references organizations(id),branch_id uuid not null references branches(id),handover_id uuid not null references handovers(id) on delete cascade,user_id uuid not null references profiles(id),participant_type participant_type not null,assignment_status text not null default 'ASSIGNED',assigned_at timestamptz not null default now(),acknowledged_at timestamptz,confirmed_at timestamptz,signature_path text,ip_address inet,user_agent text,created_at timestamptz not null default now(),created_by uuid not null references profiles(id));
create table handover_sections(id uuid primary key default gen_random_uuid(),handover_id uuid not null references handovers(id) on delete cascade,title text not null,sort_order integer not null default 0);
create table handover_items(id uuid primary key default gen_random_uuid(),handover_id uuid not null references handovers(id) on delete cascade,title text not null,details text not null,category text not null,priority item_priority not null default 'NORMAL',room_number text,created_at timestamptz not null default now(),created_by uuid references profiles(id));
create table handover_amendments(id uuid primary key default gen_random_uuid(),handover_id uuid not null references handovers(id),reason text not null,content jsonb not null,created_by uuid not null references profiles(id),created_at timestamptz not null default now());
create table room_issues(id uuid primary key default gen_random_uuid(),organization_id uuid not null references organizations(id),branch_id uuid not null references branches(id),room_number text not null,title text not null,details text,status text not null default 'OPEN',version integer not null default 1,created_at timestamptz not null default now(),created_by uuid references profiles(id));
create table guest_notes(id uuid primary key default gen_random_uuid(),organization_id uuid not null references organizations(id),branch_id uuid not null references branches(id),guest_reference text not null,note text not null,is_sensitive boolean not null default false,created_at timestamptz not null default now(),created_by uuid references profiles(id));
create table bookings(id uuid primary key default gen_random_uuid(),organization_id uuid not null references organizations(id),branch_id uuid not null references branches(id),external_reference text,guest_name text not null,room_number text,status text not null,arrival_at timestamptz,departure_at timestamptz,created_at timestamptz not null default now());
create table booking_debts(id uuid primary key default gen_random_uuid(),booking_id uuid not null references bookings(id),amount_vnd bigint not null check(amount_vnd>=0),status text not null default 'OPEN',created_at timestamptz not null default now());
create table cash_handovers(id uuid primary key default gen_random_uuid(),organization_id uuid not null references organizations(id),branch_id uuid not null references branches(id),handover_id uuid references handovers(id),actual_total_vnd bigint not null check(actual_total_vnd>=0),system_total_vnd bigint not null check(system_total_vnd>=0),difference_vnd bigint generated always as(actual_total_vnd-system_total_vnd) stored,status finance_status not null default 'DRAFT',version integer not null default 1,giver_id uuid not null references profiles(id),receiver_id uuid not null references profiles(id),created_at timestamptz not null default now());
create table cash_handover_items(id uuid primary key default gen_random_uuid(),cash_handover_id uuid not null references cash_handovers(id),category text not null,amount_vnd bigint not null check(amount_vnd>=0),description text);
create table finance_discrepancies(id uuid primary key default gen_random_uuid(),cash_handover_id uuid not null references cash_handovers(id),amount_vnd bigint not null,explanation text,status text not null default 'OPEN',created_at timestamptz not null default now());
create table reconciliation_records(id uuid primary key default gen_random_uuid(),cash_handover_id uuid not null references cash_handovers(id),adjustment_vnd bigint not null,reason text not null,actor_id uuid not null references profiles(id),created_at timestamptz not null default now());
create table assets(id uuid primary key default gen_random_uuid(),organization_id uuid not null references organizations(id),branch_id uuid not null references branches(id),code text not null,name text not null,status text not null default 'AVAILABLE',unique(branch_id,code));
create table asset_handovers(id uuid primary key default gen_random_uuid(),asset_id uuid not null references assets(id),handover_id uuid references handovers(id),giver_id uuid references profiles(id),receiver_id uuid references profiles(id),created_at timestamptz not null default now());
create table lost_found_items(id uuid primary key default gen_random_uuid(),organization_id uuid not null references organizations(id),branch_id uuid not null references branches(id),description text not null,storage_location text,status text not null default 'FOUND',created_at timestamptz not null default now(),created_by uuid references profiles(id));
create table pending_tasks(id uuid primary key default gen_random_uuid(),organization_id uuid not null references organizations(id),branch_id uuid not null references branches(id),title text not null,details text,status text not null default 'OPEN',due_at timestamptz,assigned_to uuid references profiles(id),created_at timestamptz not null default now(),created_by uuid references profiles(id));
create table checklist_templates(id uuid primary key default gen_random_uuid(),organization_id uuid not null references organizations(id),branch_id uuid references branches(id),name text not null,is_active boolean not null default true);
create table checklist_template_items(id uuid primary key default gen_random_uuid(),template_id uuid not null references checklist_templates(id),code text not null,label text not null,is_required boolean not null default true,sort_order integer not null default 0,unique(template_id,code));
create table checklist_results(id uuid primary key default gen_random_uuid(),handover_id uuid not null references handovers(id),item_code text not null,is_completed boolean not null default false,completed_by uuid references profiles(id),completed_at timestamptz,unique(handover_id,item_code));
create table confirmations(id uuid primary key default gen_random_uuid(),organization_id uuid not null references organizations(id),branch_id uuid not null references branches(id),entity_type text not null,entity_id uuid not null,confirmed_by uuid not null references profiles(id),signature_path text,confirmed_at timestamptz not null default now());
create table attachments(id uuid primary key default gen_random_uuid(),organization_id uuid not null references organizations(id),branch_id uuid not null references branches(id),entity_type text not null,entity_id uuid not null,bucket text not null,path text not null,mime_type text not null,size_bytes bigint not null check(size_bytes>0),created_by uuid not null references profiles(id),created_at timestamptz not null default now());
create table notification_preferences(id uuid primary key default gen_random_uuid(),profile_id uuid not null references profiles(id),event_type text not null,enabled boolean not null default true,unique(profile_id,event_type));
create table notifications(id uuid primary key default gen_random_uuid(),organization_id uuid not null references organizations(id),branch_id uuid references branches(id),profile_id uuid not null references profiles(id),title text not null,body text not null,event_type text not null,read_at timestamptz,idempotency_key text unique,created_at timestamptz not null default now());
create table report_exports(id uuid primary key default gen_random_uuid(),organization_id uuid not null references organizations(id),branch_id uuid references branches(id),report_type text not null,status text not null default 'PENDING',storage_path text,requested_by uuid not null references profiles(id),created_at timestamptz not null default now(),completed_at timestamptz);
create table audit_logs(id uuid primary key default gen_random_uuid(),organization_id uuid not null references organizations(id),branch_id uuid not null references branches(id),actor_id uuid not null references profiles(id),actor_role text,action text not null,entity_type text not null,entity_id uuid not null,old_values jsonb,new_values jsonb,reason text,ip_address inet,user_agent text,request_id text,created_at timestamptz not null default now());
create table outbox_events(id uuid primary key default gen_random_uuid(),aggregate_type text not null,aggregate_id uuid not null,event_type text not null,payload jsonb not null,idempotency_key text not null unique,processed_at timestamptz,created_at timestamptz not null default now());
create index handovers_filter_idx on handovers(branch_id,status,created_at desc);create index participants_history_idx on handover_participants(branch_id,user_id,participant_type,assigned_at desc);create index tasks_filter_idx on pending_tasks(branch_id,status,due_at);create index room_issues_history_idx on room_issues(branch_id,room_number,created_at desc);create index audit_filter_idx on audit_logs(branch_id,created_at desc);
create function set_updated_at() returns trigger language plpgsql as $$begin new.updated_at=now();return new;end$$;create trigger handovers_updated before update on handovers for each row execute function set_updated_at();create trigger profiles_updated before update on profiles for each row execute function set_updated_at();
create function current_branch_ids() returns setof uuid language sql stable security definer set search_path=public as $$select branch_id from branch_memberships where profile_id=auth.uid() and is_active$$;
create function prevent_audit_mutation() returns trigger language plpgsql as $$begin raise exception 'audit logs are append-only';end$$;create trigger audit_immutable before update or delete on audit_logs for each row execute function prevent_audit_mutation();
commit;
